import os, sys, tempfile, webbrowser, base64, gzip
import tkinter as tk
from tkinter import messagebox

# ══════════════════════════════════════════════════════════════
#  AUTHORISED USERS — edit this list, then rebuild the .exe
#  Use lowercase Windows usernames (type 'whoami' in CMD to find)
# ══════════════════════════════════════════════════════════════
ALLOWED_USERS = [
    "admin",
    "mohammed.ali2",
    # Add more users below:
    # "firstname.lastname",
]
# ══════════════════════════════════════════════════════════════

# HTML tool embedded — no external file needed
HTML_DATA = b""

def get_username():
    return os.environ.get("USERNAME", "").strip().lower()

def show_denied(username):
    root = tk.Tk(); root.withdraw(); root.attributes("-topmost", True)
    messagebox.showerror("Access Denied",
        f"Access Denied\n\nUser '{username}' is not authorised to use this tool.\n\nPlease contact your administrator to request access.")
    root.destroy()

def main():
    username = get_username()
    if username not in ALLOWED_USERS:
        show_denied(username or "(unknown)")
        sys.exit(1)

    # Decode and write HTML to a temp file, open in browser, then delete
    html_bytes = gzip.decompress(base64.b64decode(HTML_DATA))
    tmp = tempfile.NamedTemporaryFile(delete=False, suffix='.html', mode='wb')
    tmp.write(html_bytes)
    tmp.close()

    import threading, time
    def cleanup():
        time.sleep(5)
        try: os.unlink(tmp.name)
        except: pass

    threading.Thread(target=cleanup, daemon=True).start()
    webbrowser.open('file:///' + tmp.name.replace('\\', '/'))

    # Keep process alive briefly so browser can load
    import time; time.sleep(6)

if __name__ == "__main__":
    main()
